# --- Utility Functions ---

def sanitize_package_name(name: str) -> str:
    """
    Validate and sanitize a package name to prevent injection attacks.
    Follows PEP 508 naming conventions.
    """
    name = name.strip()
    # Normalize per PEP 503
    normalized = re.sub(r"[-_.]+", "-", name).lower()
    if not re.match(r'^[a-z0-9]([a-z0-9._-]*[a-z0-9])?$', normalized):
        raise ValueError(
            f"Invalid package name: '{name}'. "
            "Package names must follow PEP 508 conventions."
        )
    if len(normalized) > 200:
        raise ValueError(f"Package name too long: '{name}'")
    return normalized


def validate_version_spec(spec: str) -> str:
    """Validate a version specification string."""
    spec = spec.strip()
    # Allow common version specifiers
    pattern = r'^([<>=!~]+\s*[0-9][0-9a-zA-Z.*]*(\s*,\s*[<>=!~]+\s*[0-9][0-9a-zA-Z.*]*)*)?$'
    if spec and not re.match(pattern, spec):
        raise ValueError(f"Invalid version specification: '{spec}'")
    return spec


def compute_file_hash(filepath: Path, algorithm: str = "sha256") -> str:
    """Compute the hash of a file for integrity verification."""
    h = hashlib.new(algorithm)
    with open(filepath, "rb") as f:
        while True:
            chunk = f.read(8192)
            if not chunk:
                break
            h.update(chunk)
    return h.hexdigest()


def run_command(
    args: List[str],
    cwd: Optional[Path] = None,
    capture_output: bool = True,
    check: bool = True,
    timeout: int = 300,
) -> subprocess.CompletedProcess:
    """
    Run a subprocess command securely.

    Security: Uses list-based arguments (no shell=True) to prevent shell injection.
    """
    # Validate that we're not accidentally using shell features
    for arg in args:
        if not isinstance(arg, str):
            raise TypeError(f"All command arguments must be strings, got {type(arg)}")

    logger.debug("Running command: %s", " ".join(args))

    try:
        result = subprocess.run(
            args,
            cwd=cwd,
            capture_output=capture_output,
            text=True,
            check=check,
            timeout=timeout,
            # Explicitly no shell=True
        )
        return result
    except subprocess.CalledProcessError as e:
        logger.error("Command failed with exit code %d: %s", e.returncode, e.stderr)
        raise
    except subprocess.TimeoutExpired:
        logger.error("Command timed out after %d seconds: %s", timeout, " ".join(args))
        raise


def find_tool(name: str) -> Optional[str]:
    """Find a tool in PATH."""
    return shutil.which(name)


# --- Lock File Metadata ---

@dataclass
class LockFileMetadata:
    """Metadata stored in the lock file header."""
    generated_at: str
    generator_version: str
    python_version: str
    platform: str
    hash_algorithm: str
    input_file_hash: str

    def to_header(self) -> str:
        """Generate a lock file header comment block."""
        lines = [
            "#",
            "# This file is autogenerated by dependency_manager.py",
            "# Do not edit manually. Use 'python dependency_manager.py update' instead.",
            "#",
            f"# Generated at: {self.generated_at}",
            f"# Generator version: {self.generator_version}",
            f"# Python version: {self.python_version}",
            f"# Platform: {self.platform}",
            f"# Hash algorithm: {self.hash_algorithm}",
            f"# Input file hash ({self.hash_algorithm}): {self.input_file_hash}",
            "#",
            "",
        ]
        return "\n".join(lines)

    @classmethod
    def from_header(cls, content: str) -> Optional["LockFileMetadata"]:
        """Parse metadata from a lock file header."""
        fields = {}
        for line in content.splitlines():
            if not line.startswith("#"):
                break
            for key in [
                "Generated at",
                "Generator version",
                "Python version",
                "Platform",
                "Hash algorithm",
                "Input file hash",
            ]:
                if f"# {key}:" in line:
                    value = line.split(":", 1)[1].strip()
                    # Strip hash algorithm prefix from input file hash
                    if key == "Input file hash":
                        if ")" in value:
                            value = value.split(")", 1)[1].strip()
                    fields[key] = value

        if len(fields) < 4:
            return None

        return cls(
            generated_at=fields.get("Generated at", ""),
            generator_version=fields.get("Generator version", ""),
            python_version=fields.get("Python version", ""),
            platform=fields.get("Platform", ""),
            hash_algorithm=fields.get("Hash algorithm", "sha256"),
            input_file_hash=fields.get("Input file hash", ""),
        )


# --- Dependency Entry ---

@dataclass
class DependencyEntry:
    """Represents a single dependency in the lock file."""
    name: str
    version: str
    hashes: List[str] = field(default_factory=list)
    markers: Optional[str] = None
    extras: List[str] = field(default_factory=list)
    is_direct: bool = False

    def to_lock_line(self) -> str:
        """Generate a requirements.txt-compatible line with hashes."""
        parts = [f"{self.name}=={self.version}"]
        if self.extras:
            extras_str = ",".join(sorted(self.extras))
            parts = [f"{self.name}[{extras_str}]=={self.version}"]
        if self.markers:
            parts.append(f"; {self.markers}")
        for h in sorted(self.hashes):
            parts.append(f" \\\n    --hash={h}")
        line = "".join(parts)
        if self.is_direct:
            line = f"    # direct dependency\n{line}"
        return line


# --- Main Manager Class ---

class DependencyManager:
    """
    Manages Python dependency lock files with hash verification.

    Supports both pip-tools (pip-compile) and Poetry workflows.
    """

    VERSION = "1.0.0"

    def __init__(self, config: Optional[DependencyConfig] = None):
        self.config = config or DependencyConfig()
        self.config.validate()
        self._detect_tooling()

    def _detect_tooling(self) -> None:
        """Detect available dependency management tools."""
        self.has_pip_compile = find_tool("pip-compile") is not None
        self.has_poetry = find_tool("poetry") is not None
        self.has_pip_audit = find_tool("pip-audit") is not None
        self.has_pip = find_tool("pip") is not None

        # Determine project type
        self.uses_poetry = (self.config.project_root / "poetry.lock").exists() or (
            self.has_poetry
            and (self.config.project_root / "pyproject.toml").exists()
            and self._pyproject_uses_poetry()
        )
        self.uses_pip_tools = (
            (self.config.project_root / self.config.requirements_in).exists()
            or not self.uses_poetry
        )

        logger.info(
            "Detected tools - pip-compile: %s, poetry: %s, pip-audit: %s",
            self.has_pip_compile,
            self.has_poetry,
            self.has_pip_audit,
        )
        logger.info(
            "Project type - poetry: %s, pip-tools: %s",
            self.uses_poetry,
            self.uses_pip_tools,
        )

    def _pyproject_uses_poetry(self) -> bool:
        """Check if pyproject.toml uses Poetry as build backend."""
        pyproject = self.config.project_root / "pyproject.toml"
        if not pyproject.exists():
            return False
        content = pyproject.read_text(encoding="utf-8")
        return "poetry" in content.lower() and "[tool.poetry" in content

